        context_type: "resource",
        documents: [
          {
            content: doc.content,
          },
        ],
        scope: "internal",
        source: `threshold-cli-${runId}`,
        metadata: {
          fileName,
          fileType: "text/markdown",
          groupName: ["threshold-cli", runId, doc.topic],
